#include "controller.h"

/* Task-specific constants */
#define LOW_BOUND 47.0f
#define HIGH_BOUND 52.0f
#define EARLY_OFF_THRESHOLD 50.0f
#define SENSOR_TIMEOUT_MS 1000

static bool is_rising(int temp, int prev_temp) {
    return (temp > prev_temp);
}

void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle sensor timeout - turn off heater immediately */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        output.timed_out = true;
        return output;
    }

    /* Handle invalid temperature - turn off heater immediately */
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        return output;
    }

    /* Handle temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Check for early off condition: 50 <= TEMP <= 52 AND rising */
        if (input.temperature_c >= EARLY_OFF_THRESHOLD && is_rising(input.temperature_c, controller->last_temperature_c)) {
            /* Turn off heater early - this state counts as HOLDING */
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = "STATE SAFE_OFF";
            output.changed = true;
            output.timed_out = false;  /* No timeout here, just early off */
            return output;
        }

        /* Normal case: hold previous safe actuator state if within bounds */
        controller_set_safe_off(controller);
        output.heater_on = controller->heater_on;
        output.state = CONTROLLER_STATE_SAFE_OFF;  /* Reuse the stored state name */
        output.changed = (previous_heater_on != controller->heater_on) || (previous_state != CONTROLLER_STATE_SAFE_OFF);
    }

    /* Default case: turn off heater on malformed or unexpected input */
    controller_set_safe_off(controller);
    output.heater_on = false;
    output.state = CONTROLLER_STATE_SAFE_OFF;
    output.state_name = "STATE SAFE_OFF";
    output.changed = true;

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

