#include "controller.h"

/* Task-specific constants */
#define LOW_BOUND 47.0f
#define HIGH_BOUND 52.0f
#define EARLY_OFF_THRESHOLD 50.0f
#define SENSOR_TIMEOUT_MS 1000

static bool is_rising(int temp, int prev_temp) {
    return (temp > prev_temp);
}

void controller_init(control_context_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller->heater_on = false;
    controller->state = true;  /* Initialize to safe off state */
    controller->state_name = "STATE SAFE_OFF";
    controller->changed = false;
    controller->timed_out = false;
}

control_output_t controller_step(control_context_t *controller, int input_kind, int temperature_c, uint32_t now_ms)
{
    control_output_t output = {
        .heater_on = false,
        .state = true,  /* Initialize to safe off state */
        .state_name = "STATE SAFE_OFF",
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    bool previous_state = controller->state;

    if (controller == 0) {
        return output;
    }

    /* Handle sensor timeout - turn off heater immediately */
    if (input_kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller->heater_on = false;
        controller->state = true;
        controller->state_name = "STATE SAFE_OFF";
        controller->changed = true;
        controller->timed_out = true;
        return output;
    }

    /* Handle invalid temperature - turn off heater immediately */
    if (input_kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller->heater_on = false;
        controller->state = true;
        controller->state_name = "STATE SAFE_OFF";
        controller->changed = true;
        controller->timed_out = false;  /* No timeout here, just invalid input */
        return output;
    }

    /* Handle temperature input */
    if (input_kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->heater_on = false;
        controller->state = true;
        controller->state_name = "STATE SAFE_OFF";
        controller->changed = true;
        controller->timed_out = false;  /* No timeout here, just invalid input */
        return output;
    }

    /* Default case: turn off heater on malformed or unexpected input */
    controller->heater_on = false;
    controller->state = true;
    controller->state_name = "STATE SAFE_OFF";
    controller->changed = true;

    return output;
}

const char *controller_state_name(bool state)
{
    if (state) {
        return "STATE HOLDING";
    } else {
        return "STATE SAFE_OFF";
    }
}

